        'source' => 'vanta',
        'source_file' => 'resources/frameworks/vanta/raw/cmmc2.json',
        'sort_order' => 694,
        'context' => 'Changing temporary passwords to permanent passwords immediately after system logon ensures that the necessary strength of the authentication mechanism is implemented at the earliest opportunity, reducing the susceptibility to authenticator compromises.',
    ],
    [
        'framework_slug' => 'cmmc2',
        'code' => 'IA.L2-3.5.1',
        'title' => 'Identification [CUI Data]',
        'description' => 'Identify system users, processes acting on behalf of users, and devices.',
