        ],
        'source' => 'vanta',
        'source_file' => 'resources/frameworks/vanta/raw/cmmc2.json',
        'sort_order' => 697,
        'context' => 'Identification and authentication of system components and component configurations can be determined, for example, via a cryptographic hash of the component. This is also known as device attestation and known operating state or trust profile. A trust profile based on factors such as the user, authentication method, device type, and physical location is used to make dynamic decisions on authorizations to data of varying types. If device attestation is the means of identification and authentication, then it is important that patches and updates to the device are handled via a configuration management process such that the patches and updates are done securely and do not disrupt the identification and authentication of other devices. [IR 8011-1] provides guidance on using automation support to assess system configurations.',
    ],
    [
        'framework_slug' => 'cmmc2',
        'code' => 'IA.L2-3.5.4',
        'title' => 'Replay-Resistant Authentication',
        'description' => 'Employ replay-resistant authentication mechanisms for network access to privileged and non-privileged accounts.',
        'principle_id' => 'IA',
