        'sort_order' => 743,
        'context' => 'Threat awareness and risk assessment of the organization are dynamic, continuous, and inform system operations, security requirements for the system, and the security solutions employed to meet those requirements. Threat intelligence (i.e., threat information that has been aggregated, transformed, analyzed, interpreted, or enriched to help provide the necessary context for decision-making) is infused into the risk assessment processes and information security operations of the organization to identify any changes required to address the dynamic threat environment. [SP 800-30] provides guidance on risk assessments, threat assessments, and risk analyses.',
    ],
    [
        'framework_slug' => 'cmmc2',
        'code' => 'RA.L3-3.11.3e',
        'title' => 'Advanced Risk Identification',
        'description' => 'Employ advanced automation and analytics capabilities in support of analysts to predict and identify risks to organizations, systems, and system components.',
        'principle_id' => 'RA',
        'principle_name' => 'Risk Assessment',
