        'description' => 'For breaches of unsecured protected health information involving 500 or more individuals, a covered entity shall, expect as provided in §164.412, provide the notification required by paragraph (a) contemporaneously with the notice required by §164.404(a) and in the manner specified on the HHS web site.',
        'principle_id' => '164.408',
        'principle_name' => 'Notification to the Secretary',
        'variants' => [],
        'source' => 'vanta',
