    [
        'framework_slug' => 'hipaa',
        'code' => '164.410(a)(2)',
        'title' => '164.410(a)(2)',
        'description' => 'For the purposes of paragraph (1) of this section, a breach shall be treated as discovered by a business associate as of the first day on which such breach is known to the business associate or, by exercising reasonable diligence, would have been known to the business associate. A business associate shall be deemed to have knowledge of a breach if the breach is known, or by exercising reasonable diligence would have been known, to any person, other than the person committing the breach, who is an employee, officer, or other agent of the business associate (determined in accordance with the federal common law of agency).',
        'principle_id' => '164.410',
        'principle_name' => 'Notification by a business associate',
        'variants' => [],
