        'framework_slug' => 'msftSSPA',
        'code' => 'Management (Control 1)',
        'title' => 'Contracts, Agreements, and Processing Descriptions in Place',
        'description' => 'Each applicable agreement between Microsoft and the supplier (e.g., master agreement, statement of work, purchase orders and other orders) contains privacy and security data protection language with respect to Microsoft Confidential and Personal Data, as applicable, including prohibitions on the sale of Microsoft Personal Data and Processing of Microsoft Personal Data outside the direct business relationship between Microsoft and supplier. 

For companies operating as Processors or Subprocessors in connection with the Performance, with respect to Microsoft Personal Data, the agreement must include the subject-matter and duration of the Processing, the nature and purpose of the Processing, the type of Microsoft Personal Data and categories of Data Subjects and the obligations and rights of Microsoft.',
        'principle_id' => 'Section A',
        'principle_name' => 'Management',
        'variants' => [],
