        'source_file' => 'resources/frameworks/vanta/raw/nist171.json',
        'sort_order' => 3736,
        'context' => 'Inactive identifiers pose a risk to organizational information because attackers may exploit an inactive identifier to gain undetected access to organizational devices. The owners of the inactive accounts may not notice if unauthorized access to the account has been obtained.',
    ],
    [
        'framework_slug' => 'nist171',
        'code' => '3.5.7',
        'title' => 'Enforce a minimum password complexity and change of characters when new passwords are created.',
