        'sort_order' => 3747,
        'context' => 'This requirement addresses the information security aspects of system maintenance that are performed off-site and applies to all types of maintenance to any system component (including applications) conducted by a local or nonlocal entity (e.g., in-contract, warranty, in- house, software maintenance agreement).  [SP 800-88] provides guidance on media sanitization.',
    ],
    [
