        'source_file' => 'resources/frameworks/vanta/raw/nist171.json',
        'sort_order' => 3749,
        'context' => 'Nonlocal maintenance and diagnostic activities are those activities conducted by individuals communicating through an external network. The authentication techniques employed in the establishment of these nonlocal maintenance and diagnostic sessions reflect the network access requirements in 3.5.3.',
    ],
    [
        'framework_slug' => 'nist171',
        'code' => '3.7.6',
        'title' => 'Supervise the maintenance activities of maintenance personnel without required access authorization.',
        'description' => 'Supervise the maintenance activities of maintenance personnel without required access authorization.',
