        'variants' => [],
        'source' => 'vanta',
        'source_file' => 'resources/frameworks/vanta/raw/ofdss.json',
        'sort_order' => 3953,
        'context' => 'Maintaining current patch levels for critical assets ensures that they are free of vulnerabilities that could lead to their compromise.',
    ],
    [
