        'framework_slug' => 't23nycrr500',
        'code' => '500.2.a',
        'title' => 'Maintain cybersecurity program',
        'description' => 'Each Covered Entity shall maintain a cybersecurity program designed to protect the confidentiality, integrity and availability of the Covered Entity’s Information Systems.

A Covered Entity may meet the requirement(s) of this control by adopting the relevant and applicable provisions of a cybersecurity program maintained by an Affiliate, provided that such provisions satisfy the requirements of this control, as applicable to the Covered Entity.',
        'principle_id' => '500.2',
        'principle_name' => 'Cybersecurity Program',
        'variants' => [],
        'source' => 'vanta',
