    ],
    [
        'framework_slug' => 't23nycrr500',
        'code' => '500.2.b',
        'title' => 'Core cybersecurity functions',
        'description' => 'The cybersecurity program shall be based on the Covered Entity’s Risk Assessment and designed to perform the following core cybersecurity functions:
 (1) identify and assess internal and external cybersecurity risks that may threaten the security or integrity of Nonpublic Information stored on the Covered Entity’s Information Systems; 
 (2) use defensive infrastructure and the implementation of policies and procedures to protect the Covered Entity’s Information Systems, and the Nonpublic Information stored on those Information Systems, from unauthorized access, use or other malicious acts;
 (3) detect Cybersecurity Events;
 (4) respond to identified or detected Cybersecurity Events to mitigate any negative effects;
 (5) recover from Cybersecurity Events and restore normal operations and services; and
 (6) fulfill applicable regulatory reporting obligations.

A Covered Entity may meet the requirement(s) of this control by adopting the relevant and applicable provisions of a cybersecurity program maintained by an Affiliate, provided that such provisions satisfy the requirements of this control, as applicable to the Covered Entity.',
        'principle_id' => '500.2',
        'principle_name' => 'Cybersecurity Program',
        'variants' => [],
        'source' => 'vanta',
        'source_file' => 'resources/frameworks/vanta/raw/t23nycrr500.json',
        'sort_order' => 5037,
