        'framework_slug' => 't23nycrr500',
        'code' => '500.2.c',
        'title' => 'Cybersecurity documents availability',
        'description' => 'All documentation and information relevant to the Covered Entity’s cybersecurity program shall be made available to the superintendent upon request.',
        'principle_id' => '500.2',
        'principle_name' => 'Cybersecurity Program',
        'variants' => [],
        'source' => 'vanta',
