    ],
    [
        'framework_slug' => 't23nycrr500',
        'code' => '500.3.a',
        'title' => 'Cybersecurity policies',
        'description' => 'Each Covered Entity shall implement and maintain a written policy or policies, approved by a Senior Officer or the Covered Entity’s board of directors (or an appropriate committee thereof) or equivalent governing body, setting forth the Covered Entity’s policies and procedures for the protection of its Information Systems and Nonpublic Information stored on those Information Systems. The cybersecurity policy shall be based on the Covered Entity’s Risk Assessment and address the following areas to the extent applicable to the Covered Entity’s operations:
 (a) information security;
 (b) data governance and classification;
 (c) asset inventory and device management;
 (d) access controls and identity management;
 (e) business continuity and disaster recovery planning and resources;
 (f) systems operations and availability concerns;
 (g) systems and network security;
 (h) systems and network monitoring;
 (i) systems and application development and quality assurance;
 (j) physical security and environmental controls;
 (k) customer data privacy;
 (l) vendor and Third Party Service Provider management;
 (m) risk assessment; and
 (n) incident response.',
        'principle_id' => '500.3',
        'principle_name' => 'Cybersecurity Policy',
        'variants' => [],
        'source' => 'vanta',
        'source_file' => 'resources/frameworks/vanta/raw/t23nycrr500.json',
        'sort_order' => 5039,
    ],
    [
        'framework_slug' => 't23nycrr500',
        'code' => '500.4.a',
        'title' => 'Cybersecurity leadership designation',
        'description' => 'Each Covered Entity shall designate a qualified individual responsible for overseeing and implementing the Covered Entity’s cybersecurity program and enforcing its cybersecurity policy (for purposes of this control, “Chief Information Security Officer” or “CISO”). The CISO may be employed by the Covered Entity, one of its Affiliates or a Third Party Service Provider. To the extent this requirement is met using a Third Party Service Provider or an Affiliate, the Covered Entity shall:
 (1) retain responsibility for compliance with this control;
 (2) designate a senior member of the Covered Entity’s personnel responsible for direction and oversight of the Third Party Service Provider; and
 (3) require the Third Party Service Provider to maintain a cybersecurity program that protects the Covered Entity in accordance with the requirements of this control.',
        'principle_id' => '500.4',
        'principle_name' => 'Chief Information Security Officer',
        'variants' => [],
        'source' => 'vanta',
        'source_file' => 'resources/frameworks/vanta/raw/t23nycrr500.json',
        'sort_order' => 5040,
    ],
    [
        'framework_slug' => 't23nycrr500',
        'code' => '500.4.b',
        'title' => 'CISO annual reporting',
        'description' => 'The CISO of each Covered Entity shall report in writing at least annually to the Covered Entity’s board of directors or equivalent governing body. If no such board of directors or equivalent governing body exists, such report shall be timely presented to a Senior Officer of the Covered Entity responsible for the Covered Entity’s cybersecurity program. The CISO shall report on the Covered Entity’s cybersecurity program and material cybersecurity risks. The CISO shall consider to the extent applicable:
 (1) the confidentiality of Nonpublic Information and the integrity and security of the Covered Entity’s Information Systems;
 (2) the Covered Entity’s cybersecurity policies and procedures;
 (3) material cybersecurity risks to the Covered Entity;
 (4) overall effectiveness of the Covered Entity’s cybersecurity program; and
 (5) material Cybersecurity Events involving the Covered Entity during the time period addressed by the report.',
        'principle_id' => '500.4',
        'principle_name' => 'Chief Information Security Officer',
        'variants' => [],
        'source' => 'vanta',
        'source_file' => 'resources/frameworks/vanta/raw/t23nycrr500.json',
        'sort_order' => 5041,
    ],
    [
        'framework_slug' => 't23nycrr500',
        'code' => '500.5.a',
        'title' => 'Cybersecurity monitoring and testing',
        'description' => 'The cybersecurity program for each Covered Entity shall include monitoring and testing, developed in accordance with the Covered Entity’s Risk Assessment, designed to assess the effectiveness of the Covered Entity’s cybersecurity program. The monitoring and testing shall include continuous monitoring or periodic Penetration Testing and vulnerability assessments. 

Covered entities shall:
(a) annual Penetration Testing of the Covered Entity’s Information Systems determined each given year based on relevant identified risks in accordance with the Risk Assessment; and
(b) bi-annual vulnerability assessments, including any systematic scans or reviews of Information Systems reasonably designed to identify publicly known cybersecurity vulnerabilities in the Covered Entity’s Information Systems based on the Risk Assessment.',
        'principle_id' => '500.5',
        'principle_name' => 'Penetration Testing and Vulnerability Assessments',
        'variants' => [],
        'source' => 'vanta',
        'source_file' => 'resources/frameworks/vanta/raw/t23nycrr500.json',
        'sort_order' => 5042,
