    ],
    [
        'framework_slug' => 't23nycrr500',
        'code' => '500.9.b',
        'title' => 'Risk assessment criteria',
        'description' => 'The Risk Assessment shall be carried out in accordance with written policies and procedures and shall be documented. Such policies and procedures shall include:
 (1) criteria for the evaluation and categorization of identified cybersecurity risks or threats facing the Covered Entity;
 (2) criteria for the assessment of the confidentiality, integrity, security and availability of the Covered Entity’s Information Systems and Nonpublic Information, including the adequacy of existing controls in the context of identified risks; and
 (3) requirements describing how identified risks will be mitigated or accepted based on the Risk Assessment and how the cybersecurity program will address the risks.',
        'principle_id' => '500.9',
        'principle_name' => 'Risk Assessment',
        'variants' => [],
        'source' => 'vanta',
        'source_file' => 'resources/frameworks/vanta/raw/t23nycrr500.json',
        'sort_order' => 5050,
    ],
    [
        'framework_slug' => 't23nycrr500',
        'code' => '500.10.a',
        'title' => 'Qualified cybersecurity personnel',
        'description' => 'Covered Entities shall: 
 (1) utilize qualified cybersecurity personnel of the Covered Entity, an Affiliate or a Third Party Service Provider sufficient to manage the Covered Entity’s cybersecurity risks and to perform or oversee the performance of the core cybersecurity functions specified in control 500.2(b)(1)-(6);
 (2) provide cybersecurity personnel with cybersecurity updates and training sufficient to address relevant cybersecurity risks; and
 (3) verify that key cybersecurity personnel take steps to maintain current knowledge of changing cybersecurity threats and countermeasures.',
        'principle_id' => '500.10',
        'principle_name' => 'Cybersecurity Personnel and Intelligence',
        'variants' => [],
        'source' => 'vanta',
        'source_file' => 'resources/frameworks/vanta/raw/t23nycrr500.json',
        'sort_order' => 5051,
    ],
    [
        'framework_slug' => 't23nycrr500',
        'code' => '500.11.a',
        'title' => 'Third-party cybersecurity policies',
        'description' => 'Each Covered Entity shall implement written policies and procedures designed to ensure the security of Information Systems and Nonpublic Information that are accessible to, or held by, Third Party Service Providers. Such policies and procedures shall be based on the Risk Assessment of the Covered Entity and shall address to the extent applicable:
 (1) the identification and risk assessment of Third Party Service Providers;
 (2) minimum cybersecurity practices required to be met by such Third Party Service Providers in order for them to do business with the Covered Entity;
 (3) due diligence processes used to evaluate the adequacy of cybersecurity practices of such Third Party Service Providers; and
 (4) periodic assessment of such Third Party Service Providers based on the risk they present and the continued adequacy of their cybersecurity practices.

An agent, employee, representative or designee of a Covered Entity who is itself a Covered Entity need not develop its own Third Party Information Security Policy pursuant to this section if the agent, employee, representative or designee follows the policy of the Covered Entity that is required to comply with this control.',
        'principle_id' => '500.11',
        'principle_name' => 'Third Party Service Provider Security Policy',
        'variants' => [],
        'source' => 'vanta',
        'source_file' => 'resources/frameworks/vanta/raw/t23nycrr500.json',
        'sort_order' => 5052,
    ],
    [
        'framework_slug' => 't23nycrr500',
        'code' => '500.11.b',
        'title' => 'Third-party cybersecurity policies guidelines',
        'description' => 'Policies and procedures outlined in control 500.11.a shall include relevant guidelines for due diligence and/or contractual protections relating to Third Party Service Providers including to the extent applicable guidelines addressing:
 (1) the Third Party Service Provider’s policies and procedures for access controls, including its use of Multi-Factor Authentication as required by section 500.12 of this control, to limit access to relevant Information Systems and on public Information;
 (2) the Third Party Service Provider’s policies and procedures for use of encryption as required by section 500.15(a)-(b) to protect Nonpublic Information in transit and at rest;
 (3) notice to be provided to the Covered Entity in the event of a Cybersecurity Event directly impacting the Covered Entity’s Information Systems or the Covered Entity’s Nonpublic Information being held by the Third Party Service Provider; and
 (4) representations and warranties addressing the Third Party Service Provider’s cybersecurity policies and procedures that relate to the security of the Covered Entity’s Information Systems or Nonpublic Information.

An agent, employee, representative or designee of a Covered Entity who is itself a Covered Entity need not develop its own Third Party Information Security Policy pursuant to this section if the agent, employee, representative or designee follows the policy of the Covered Entity that is required to comply with this control.',
        'principle_id' => '500.11',
        'principle_name' => 'Third Party Service Provider Security Policy',
        'variants' => [],
        'source' => 'vanta',
        'source_file' => 'resources/frameworks/vanta/raw/t23nycrr500.json',
        'sort_order' => 5053,
    ],
    [
        'framework_slug' => 't23nycrr500',
        'code' => '500.12.a',
        'title' => 'Risk-based access control',
        'description' => 'Based on its Risk Assessment, each Covered Entity shall use effective controls, which may include Multi-Factor Authentication or Risk-Based Authentication, to protect against unauthorized access to Nonpublic Information or Information Systems.',
        'principle_id' => '500.12',
        'principle_name' => 'Multi-Factor Authentication',
