        'code' => '500.12.b',
        'title' => 'Multi-factor authentication',
        'description' => 'Multi-Factor Authentication shall be utilized for any individual accessing the Covered Entity’s internal networks from an external network, unless the Covered Entity’s CISO has approved in writing the use of reasonably equivalent or more secure access controls.',
        'principle_id' => '500.12',
