    [
        'framework_slug' => 't23nycrr500',
        'code' => '500.13.a',
        'title' => 'Data disposal',
        'description' => 'As part of its cybersecurity program, each Covered Entity shall include policies and procedures for the secure disposal on a periodic basis of any Nonpublic Information as defined by NYCRR 500, section 500.1(g)(2)-(3) that is no longer necessary for business operations or for other legitimate business purposes of the Covered Entity, except where such information is otherwise required to be retained by law or regulation, or where targeted disposal is not reasonably feasible due to the manner in which the information is maintained.',
        'principle_id' => '500.13',
        'principle_name' => 'Limitations on Data Retention',
