    [
        'framework_slug' => 't23nycrr500',
        'code' => '500.14.a',
        'title' => 'Activity monitoring',
        'description' => 'As part of its cybersecurity program, each Covered Entity shall: implement risk-based policies, procedures and controls designed to monitor the activity of Authorized Users and detect unauthorized access or use of, or tampering with, Nonpublic Information by such Authorized Users.',
        'principle_id' => '500.14',
        'principle_name' => 'Training and Monitoring',
