        'code' => '500.14.b',
        'title' => 'Cybersecurity awareness training',
        'description' => 'As part of its cybersecurity program, each Covered Entity shall: provide regular cybersecurity awareness training for all personnel that is updated to reflect risks identified by the Covered Entity in its Risk Assessment.',
        'principle_id' => '500.14',
        'principle_name' => 'Training and Monitoring',
        'variants' => [],
