        'framework_slug' => 't23nycrr500',
        'code' => '500.15.b',
        'title' => 'Encryption feasibility review',
        'description' => 'To the extent that a Covered Entity is utilizing compensating controls relevant to control 500.15.a, the feasibility of encryption and effectiveness of the compensating controls shall be reviewed by the CISO at least annually.',
        'principle_id' => '500.15',
        'principle_name' => 'Encryption of Nonpublic Information',
