    [
        'framework_slug' => 't23nycrr500',
        'code' => '500.16.a',
        'title' => 'Incident response strategies',
        'description' => 'As part of its cybersecurity program, each Covered Entity shall establish a written incident response plan designed to promptly respond to, and recover from, any Cybersecurity Event materially affecting the confidentiality, integrity or availability of the Covered Entity’s Information Systems or the continuing functionality of any aspect of the Covered Entity’s business or operations.',
        'principle_id' => '500.16',
        'principle_name' => 'Incident Response Plan',
        'variants' => [],
        'source' => 'vanta',
        'source_file' => 'resources/frameworks/vanta/raw/t23nycrr500.json',
        'sort_order' => 5061,
    ],
    [
        'framework_slug' => 't23nycrr500',
        'code' => '500.16.b',
        'title' => 'Incident response procedures',
        'description' => 'Such incident response plan shall address the following areas:
 (1) the internal processes for responding to a Cybersecurity Event;
 (2) the goals of the incident response plan;
 (3) the definition of clear roles, responsibilities and levels of decision-making authority;
 (4) external and internal communications and information sharing;
 (5) identification of requirements for the remediation of any identified weaknesses in Information Systems and associated controls;
 (6) documentation and reporting regarding Cybersecurity Events and related incident response activities;
 (7) the evaluation and revision as necessary of the incident response plan following a Cybersecurity Event.',
        'principle_id' => '500.16',
        'principle_name' => 'Incident Response Plan',
        'variants' => [],
        'source' => 'vanta',
        'source_file' => 'resources/frameworks/vanta/raw/t23nycrr500.json',
        'sort_order' => 5062,
    ],
    [
        'framework_slug' => 't23nycrr500',
        'code' => '500.17.a',
        'title' => 'Cybersecurity event notification',
        'description' => 'Notice of Cybersecurity Event. Each Covered Entity shall notify the superintendent as promptly as possible but in no event later than 72 hours from a determination that a Cybersecurity Event has occurred that is either of the following:
 (1) Cybersecurity Events impacting the Covered Entity of which notice is required to be provided to any
 government body, self-regulatory agency or any other supervisory body; or
 (2) Cybersecurity Events that have a reasonable likelihood of materially harming any material part of the
 normal operation(s) of the Covered Entity.',
        'principle_id' => '500.17',
        'principle_name' => 'Notices to Superintendent',
        'variants' => [],
        'source' => 'vanta',
        'source_file' => 'resources/frameworks/vanta/raw/t23nycrr500.json',
        'sort_order' => 5063,
    ],
    [
        'framework_slug' => 't23nycrr500',
        'code' => '500.17.b',
        'title' => 'Annual compliance certification',
        'description' => 'Annually each Covered Entity shall submit to the superintendent a written statement covering the prior calendar year. This statement shall be submitted by April 15th in such form set forth as Appendix A of Title 23 part 500, certifying that the Covered Entity is in compliance with the requirements set forth in this control. Each Covered Entity shall maintain for examination by the Department all records, schedules and data supporting this certificate for a period of five years. To the extent a Covered Entity has identified areas, systems or processes that require material improvement, updating or redesign, the Covered Entity shall document the identification and the remedial efforts planned and underway to address such areas, systems or processes. Such documentation must be available for inspection by the superintendent.',
        'principle_id' => '500.17',
        'principle_name' => 'Notices to Superintendent',
